oxy_webhelp_navlinks = {"ncd_data_sets-d27243e38029":{"topics":[{"title":"Data protection and Recovery using <span class=\"ph\">RSC<\/span> and <span class=\"ph\">NAS CD<\/span>","shortdesc":"<p class=\"shortdesc\">You can manage your <span class=\"ph\">NAS CD<\/span> datasets depending on whether you import or         set up the NAS systems in <span class=\"ph\">NAS CD<\/span> or <span class=\"ph\">RSC<\/span>.<\/p>","href":"rncd\/rncd_data_protection_mgmt_using_rsc_ncd.html","attributes":{"data-id":"rncd_data_protection_mgmt_using_rsc_ncd"},"menu":{"hasChildren":false},"tocID":"rncd_data_protection_mgmt_using_rsc_ncd-d27243e38044","topics":[]},{"title":"Set up <span class=\"ph\">NAS CD<\/span> data sets from <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\">You can set up and protect your <span class=\"ph\">NAS CD<\/span> data sets from the <span class=\"ph\">RSC<\/span>.<\/p>","href":"rncd\/rncd_setup_ncd_datasets_rsc.html","attributes":{"data-id":"rncd_setup_ncd_datasets_rsc"},"menu":{"hasChildren":false},"tocID":"rncd_setup_ncd_datasets_rsc-d27243e38069","next":"rncd_setup_ncd_datasets_rsc-d27243e38069"},{"title":"Set up <span class=\"ph\">NAS CD<\/span> datasets from <span class=\"ph\">NAS CD<\/span>","shortdesc":"<p class=\"shortdesc\">You can set up and protect your <span class=\"ph\">NAS CD<\/span> data sets from the <span class=\"ph\">NAS CD<\/span>.<\/p>","href":"rncd\/rncd_setup_datasets_ncd.html","attributes":{"data-id":"rncd_setup_datasets_ncd"},"menu":{"hasChildren":false},"tocID":"rncd_setup_datasets_ncd-d27243e39251","next":"rncd_setup_datasets_ncd-d27243e39251"},{"title":"Unstructured Data dashboard","shortdesc":"<p class=\"shortdesc\">The Unstructured Data dashboard in <span class=\"ph\">RSC<\/span> provides a comprehensive data         protection summary for all connected clusters, displaying statistics on data collection,         archive usage, storage, and the status of protected files and shares.<\/p>","href":"saas\/ncd_unstructured_data_dashboard.html","attributes":{"data-id":"ncd_unstructured_data_dashboard"},"menu":{"hasChildren":false},"tocID":"ncd_unstructured_data_dashboard-d27243e39608","next":"ncd_unstructured_data_dashboard-d27243e39608"},{"title":"Data Observability for <span class=\"ph\">NAS CD<\/span> data sets","shortdesc":"<p class=\"shortdesc\"> To provide Data Observability, you can enable <span class=\"ph\">Data Threat Analytics<\/span> and         configure <span class=\"ph\">Data Security Posture<\/span> for <span class=\"ph\">NAS CD<\/span> data sets. <span class=\"ph\">Data Threat Analytics<\/span> detects ransomware attacks and <span class=\"ph\">Data Security Posture<\/span> identifies sensitive data in your <span class=\"ph\">NAS CD<\/span> data sets.<\/p>","href":"saas\/ncd_data_observability.html","attributes":{"data-id":"ncd_data_observability"},"menu":{"hasChildren":false},"tocID":"ncd_data_observability-d27243e39656","next":"ncd_data_observability-d27243e39656"},{"title":"<span class=\"ph\">RSC<\/span> API proxy for <span class=\"ph\">NAS CD<\/span> REST API","shortdesc":"<p class=\"shortdesc\">Using the <span class=\"ph\">RSC<\/span> API proxy, you can send <span class=\"ph\">NAS CD<\/span> REST API         requests directly to an <span class=\"ph\">RSC<\/span> instance instead of a <span class=\"ph\">NAS CD<\/span>         instance. This simplifies data management across <span class=\"ph\">NAS CD<\/span> clusters and         streamlines API interactions, reduces complexity, and enables efficient management of <span class=\"ph\">NAS CD<\/span> data from a single, secure location.<\/p>","href":"saas\/rsc_api_proxy_nascd_rest_api.html","attributes":{"data-id":"rsc_api_proxy_nascd_rest_api"},"menu":{"hasChildren":false},"tocID":"rsc_api_proxy_nascd_rest_api-d27243e39871","next":"rsc_api_proxy_nascd_rest_api-d27243e39871"}]}};